function renderHerbCard(herb){
const w={s:'82%',m:'56%',p:'34%'};
return`<a class="herb-card" href="/herb/${herb.id}"><div class="herb-card-sketch">${getSketch(herb.id)}</div><div class="herb-card-body"><div class="herb-card-name">${herb.name} <span class="zh">(${herb.zh})</span></div><div class="herb-card-latin">${herb.latin}</div><div class="herb-card-tags">${herb.tags.map(t=>`<span class="tag tag-jade">${t}</span>`).join('')}</div><div class="ev-bar-row"><span class="ev-bar-label">Evidence</span><div class="ev-track"><div class="ev-fill ev-fill-${herb.ev}" style="width:${w[herb.ev]}"></div></div><span class="ev-bar-label">${herb.evLabel}</span></div><div class="herb-card-footer"><span class="herb-card-studies">${herb.studies} studies ${herb.rcts} RCTs</span><span class="herb-card-cta">View dossier &#8594;</span></div></div></a>`;}

function toggleMega(which,btn){
const ids={body:'mega-body',goals:'mega-goals',formulary:'mega-formulary'};
const target=document.getElementById(ids[which]);if(!target)return;
const isOpen=target.classList.contains('open');
document.querySelectorAll('.mega').forEach(m=>m.classList.remove('open'));
document.querySelectorAll('.nav-btn').forEach(b=>b.classList.remove('active'));
if(!isOpen){target.classList.add('open');btn.classList.add('active');setTimeout(()=>{function outside(e){if(!document.querySelector('.site-header').contains(e.target)){document.querySelectorAll('.mega').forEach(m=>m.classList.remove('open'));document.querySelectorAll('.nav-btn').forEach(b=>b.classList.remove('active'));document.removeEventListener('click',outside);}}document.addEventListener('click',outside);},0);}
}

function selectOrgan(key,el){
document.querySelectorAll('.organ-item').forEach(x=>{x.style.background='';x.style.color='';});
el.style.background='var(--jade-l)';el.style.color='var(--jade-d)';
const d=ORGAN_DATA[key];if(!d)return;
const t=document.getElementById('organ-title');if(t)t.textContent=d.title;
const n=document.getElementById('organ-note');if(n)n.textContent=d.note;
const c=document.getElementById('organ-chips');
if(c)c.innerHTML=d.herbs.map(h=>`<a href="/herb/${h.id}" style="display:inline-flex;align-items:center;gap:5px;font-size:11px;padding:5px 10px;border-radius:5px;border:0.5px solid var(--border-m);color:var(--ink2);text-decoration:none;transition:all .12s" onmouseover="this.style.borderColor='var(--jade)';this.style.background='var(--jade-l)'" onmouseout="this.style.borderColor='var(--border-m)';this.style.background=''"><span style="width:5px;height:5px;border-radius:50%;background:${h.ev==='s'?'var(--jade)':h.ev==='m'?'#5DCAA5':'var(--amber)'};flex-shrink:0"></span>${h.n} <span style="font-family:var(--mono);font-size:9px;color:var(--ink4)">${h.zh}</span></a>`).join('');
}

function navSearch(val){if(val.length<2)return;window.location.href=`formulary.html?q=${encodeURIComponent(val)}`;}

function initMegas(){
const first=document.querySelector('.organ-item');if(first)selectOrgan('liver',first);
const gg=document.getElementById('goals-mega-grid');
const MISSING_PROTOCOLS=new Set(['sleep','energy','gut-health','anti-ageing','eye-health','respiratory']);
if(gg)gg.innerHTML=GOALS.map(g=>{
  const missing=MISSING_PROTOCOLS.has(g.id);
  if(missing){
    return `<div style="border:0.5px solid var(--border);border-radius:8px;padding:10px 12px;display:block;opacity:0.45;cursor:default;position:relative">
      <div style="font-size:12px;font-weight:500;color:var(--ink);margin-bottom:3px">${g.name}</div>
      <div style="font-family:var(--mono);font-size:9px;color:var(--ink3)">${g.tags.slice(0,2).join(' ')}</div>
      <span style="position:absolute;top:8px;right:8px;font-family:var(--mono);font-size:8px;letter-spacing:0.1em;text-transform:uppercase;color:var(--ink4);background:var(--cream2);padding:2px 6px;border-radius:3px">Soon</span>
    </div>`;
  }
  return `<a href="formulary.html?goal=${g.id}" style="border:0.5px solid var(--border);border-radius:8px;padding:10px 12px;display:block;text-decoration:none;transition:all .15s" onmouseover="this.style.borderColor='var(--jade)';this.style.background='var(--jade-l)'" onmouseout="this.style.borderColor='var(--border)';this.style.background=''"><div style="font-size:12px;font-weight:500;color:var(--ink);margin-bottom:3px">${g.name}</div><div style="font-family:var(--mono);font-size:9px;color:var(--ink3)">${g.tags.slice(0,2).join(' ')}</div></a>`;
}).join('');
if(location.hash&&location.pathname.includes('protocols')){setTimeout(()=>{const el=document.getElementById(location.hash.slice(1));if(el)el.scrollIntoView({behavior:'smooth'});},300);}
}

function toggleMobileNav(){
const header=document.querySelector('.site-header');
const ham=document.getElementById('nav-ham');
if(!header||!ham)return;
header.classList.toggle('nav-mobile-open');
}
