window.HERBS=HERBS;window.GOALS=GOALS;window.ORGAN_DATA=ORGAN_DATA;window.HERB_COUNT=HERB_COUNT;window.getSketch=getSketch;window.renderNav=renderNav;window.renderFooter=renderFooter;window.renderHerbCard=renderHerbCard;window.toggleMega=toggleMega;window.selectOrgan=selectOrgan;window.navSearch=navSearch;window.initMegas=initMegas;
